def agent_execute_tool(tool_name, *args):
    if tool_name == "execute":
        return eval(args[0])
    elif tool_name == "query_db":
        return db.query(args[0])
    elif tool_name == "delete_file":
        return os.remove(args[0])

def process_agent_action(action, tool_name, args):
    if action == 'execute_tool':
        return agent_execute_tool(tool_name, *args)

