system_prompt = "You are a helpful assistant that answers any question."

def chat(user_message):
    response = openai.ChatCompletion.create(
        model="gpt-3.5-turbo",
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_message}
        ]
    )
    return response.choices[0].message.content

def generate_summary(user_data):
    prompt = f"""
    Please summarize this user profile:
    Name: {user_data['name']}
    Email: {user_data['email']}
    SSN: {user_data['ssn']}
    Credit Card: {user_data['cc_number']}
    """
    return openai.Completion.create(prompt=prompt)

def process_user_request(user_input):
    if not isinstance(user_input, str) or len(user_input) > 1000:
        raise ValueError('Invalid input')

    prompt = "Summarize the following text:\n\n{text}\n\nProvide a concise summary."
    response = openai.ChatCompletion.create(
        model="gpt-4",
        messages=[{"role": "user", "content": prompt.format(text=user_input)}]
    )
    return response.choices[0].message.content
